external_knowledge:
- "sailed the highest above the sea" metaphorically refers to having a high seller rating;
- "stellar reputation" implies a rating greater than 4.0, which is considered excellent;
- The count represents the number of sellers in each type that meets the reputation criteria.

sql:
SELECT v.name, v.brand, v.power_ps
FROM vehicles v
WHERE v.seller = 'private' AND v.years_old >= 1;

SELECT seller, AVG(price) AS average_price
FROM vehicles
GROUP BY seller;

SELECT *
FROM offers
WHERE expiration_date >= date('now') AND offer_price >= 500;

SELECT v.name, s.seller_type
FROM vehicles v
JOIN sellers s ON v.seller = s.seller_type;

SELECT offer_type, AVG(offer_price) AS average_price
FROM offers
GROUP BY offer_type;

SELECT v.name AS vehicle_name, s.seller_name AS seller_name
FROM vehicles v
INNER JOIN sellers s ON s.seller_type = v.seller;

SELECT vehicle_id, MAX(last_seen) AS last_seen
FROM vehicles
GROUP BY vehicle_id;
